using System;

class Program
{
    static void Main()
    {
        Span<nint> nints = stackalloc nint[4];
        nints[0] = 42;
        nints[1] = nint.MaxValue;
        Console.WriteLine($"Span<nint>: [{nints[0]}, {nints[1]}, {nints[2]}, {nints[3]}]");
        Console.WriteLine($"nint size: {sizeof(nint)} bytes");

        Span<nuint> nuints = stackalloc nuint[3];
        nuints[0] = 100;
        nuints[1] = nuint.MaxValue;
        Console.WriteLine($"Span<nuint>: [{nuints[0]}, {nuints[1]}, {nuints[2]}]");
        Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

        Console.WriteLine("Success: stackalloc Span<nint> and Span<nuint> both work.");
    }
}
EOF
